            { word: "नासिकाच्छेदनम्", transliteration: "nāsikācchēdanam", meaning: "cutting off of the nose" },
            { word: "कर्णयोः", transliteration: "karṇayōḥ", meaning: "of the two ears" },
            { word: "विरूपणम्", transliteration: "virūpaṇam", meaning: "disfigurement, mutilation" }
