            { word: "निमिषार्धेन", transliteration: "nimiṣārdhēna", meaning: "in half a blink of an eye" },
            { word: "खरम्", transliteration: "kharam", meaning: "Khara" },
            { word: "दूषणम्", transliteration: "dūṣaṇam", meaning: "Dushana" }
